function parseCSVLine(line) {
  if (typeof line !== "string") return null;

  const fields = [];
  let i = 0;

  while (true) {
    let field = "";

    if (line[i] === '"') {
      // Quoted field
      i++;
      let closed = false;
      while (i < line.length) {
        if (line[i] === '"') {
          if (line[i + 1] === '"') {
            field += '"';
            i += 2;
          } else {
            i++;
            closed = true;
            break;
          }
        } else {
          field += line[i];
          i++;
        }
      }
      if (!closed) return null; // unterminated quote
      // Only a comma or end-of-line may follow a closing quote
      if (i < line.length && line[i] !== ",") return null;
    } else {
      // Unquoted field
      while (i < line.length && line[i] !== ",") {
        if (line[i] === '"') return null; // quote inside unquoted field
        field += line[i];
        i++;
      }
    }

    fields.push(field);

    if (i >= line.length) break;
    i++; // skip the comma; a trailing comma yields a final empty field
    if (i >= line.length) {
      fields.push("");
      break;
    }
  }

  return fields;
}
